interface IconProps {
  size?: number;
}

const defaults: Required<IconProps> = { size: 20 };

function svgBase(props: IconProps) {
  const s = props.size ?? defaults.size;
  return {
    width: s,
    height: s,
    viewBox: '0 0 20 20',
    xmlns: 'http://www.w3.org/2000/svg',
  };
}

const WHITE_STROKE = {
  stroke: '#FFFFFF',
  strokeWidth: 1.5,
  strokeLinecap: 'round' as const,
  strokeLinejoin: 'round' as const,
  fill: 'none',
};

export function ClipboardIcon(props: IconProps = {}) {
  return (
    <svg {...svgBase(props)}>
      <defs>
        <linearGradient id="clipboard-bg" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="#FFD60A" />
          <stop offset="100%" stopColor="#FF9F0A" />
        </linearGradient>
      </defs>
      <rect
        x="1"
        y="1"
        width="18"
        height="18"
        rx="4"
        fill="url(#clipboard-bg)"
      />
      <rect
        x="7"
        y="4"
        width="6"
        height="2"
        rx="0.75"
        {...WHITE_STROKE}
        strokeWidth={1.2}
      />
      <rect
        x="5.5"
        y="5.5"
        width="9"
        height="10"
        rx="1.5"
        {...WHITE_STROKE}
        strokeWidth={1.2}
      />
      <line
        x1="7.5"
        y1="9.5"
        x2="12.5"
        y2="9.5"
        {...WHITE_STROKE}
        strokeWidth={1.2}
      />
      <line
        x1="7.5"
        y1="12"
        x2="11"
        y2="12"
        {...WHITE_STROKE}
        strokeWidth={1.2}
      />
    </svg>
  );
}

